mapper.select:
with t_add as ( select transcription_id, transcriber_id, op from ( values
(#{tt.transcriptionId}::bigint, #{tt.transcriberId}::bigint, 'ADD')
) as t(transcription_id, transcriber_id, op) ), t_del as ( select transcription_id, transcriber_id, 'DEL' as op from transcription_transcriber tt where exists (select * from t_add where t_add.transcription_id = tt.transcription_id) ) merge into transcription_transcriber tt using ( select transcription_id, transcriber_id, op from t_del where not exists (select * from t_add where t_add.transcription_id = t_del.transcription_id and t_add.transcriber_id = t_del.transcriber_id) union all select transcription_id, transcriber_id, op from t_add ) as s on (tt.transcription_id = s.transcription_id and tt.transcriber_id = s.transcriber_id) when matched and s.op = 'ADD' then do nothing when matched and s.op = 'DEL' then delete when not matched then insert (transcription_id, transcriber_id) values (s.transcription_id, s.transcriber_id) returning tt.transcription_id, tt.transcriber_id, merge_action() as action
